<template>
  <div class="agent-form-container" v-loading="isLoading">
    <div class="page-header">
      <h1>{{ isEditMode ? '编辑智能体' : '创建智能体' }}</h1>
      <el-button @click="$router.push('/agents')">
        <el-icon><back /></el-icon> 返回列表
      </el-button>
    </div>

    <el-alert
      v-if="error"
      :title="error"
      type="error"
      :closable="false"
      show-icon
      class="alert-margin"
    />

    <el-form
      ref="agentForm"
      :model="formData"
      :rules="rules"
      label-position="top"
      class="agent-form"
    >
      <el-card class="form-card">
        <template #header>
          <div class="card-header">
            <h2>基本信息</h2>
          </div>
        </template>

        <el-form-item label="名称" prop="name">
          <el-input v-model="formData.name" placeholder="请输入智能体名称" />
        </el-form-item>

        <el-form-item label="描述" prop="description">
          <el-input
            v-model="formData.description"
            type="textarea"
            :rows="3"
            placeholder="请输入智能体描述"
          />
        </el-form-item>

        <el-row :gutter="20">
          <el-col :xs="24" :sm="12">
            <el-form-item label="智能体类型" prop="agent_type">
              <el-select v-model="formData.agent_type" placeholder="请选择智能体类型" style="width: 100%">
                <el-option label="GPT-3.5" value="gpt-3.5" />
                <el-option label="GPT-4" value="gpt-4" />
                <el-option label="Claude 3" value="claude-3" />
                <el-option label="Gemini" value="gemini" />
                <el-option label="自定义" value="custom" />
                <el-option label="A2A兼容" value="a2a" />
              </el-select>
            </el-form-item>
          </el-col>
          <el-col :xs="24" :sm="12">
            <el-form-item label="模型名称" prop="model_name">
              <el-input v-model="formData.model_name" placeholder="请输入模型名称" />
            </el-form-item>
          </el-col>
        </el-row>

        <el-form-item label="状态" prop="is_active">
          <el-switch
            v-model="formData.is_active"
            active-text="激活"
            inactive-text="未激活"
          />
        </el-form-item>
      </el-card>

      <el-card class="form-card">
        <template #header>
          <div class="card-header">
            <h2>凭证信息</h2>
            <el-tooltip content="API密钥会被加密存储">
              <el-icon><info-filled /></el-icon>
            </el-tooltip>
          </div>
        </template>

        <el-alert
          title="凭证信息会被安全加密存储"
          type="info"
          :closable="false"
          class="alert-margin"
        />

        <el-form-item label="API密钥" prop="api_key">
          <el-input 
            v-model="formData.api_key" 
            placeholder="请输入API密钥" 
            show-password
          />
        </el-form-item>

        <el-form-item label="API端点" prop="api_endpoint">
          <el-input 
            v-model="formData.api_endpoint" 
            placeholder="请输入API端点URL（如有）"
          />
        </el-form-item>

        <el-form-item label="附加参数" prop="additional_params">
          <el-input
            v-model="formData.additional_params_text"
            type="textarea"
            :rows="4"
            placeholder="请输入附加参数（JSON格式）"
          />
        </el-form-item>
      </el-card>

      <el-card class="form-card">
        <template #header>
          <div class="card-header">
            <h2>A2A协议设置</h2>
            <el-switch
              v-model="formData.is_a2a_compliant"
              active-text="启用A2A协议"
              inactive-text="不启用"
            />
          </div>
        </template>

        <template v-if="formData.is_a2a_compliant">
          <el-form-item label="A2A端点URL" prop="a2a_endpoint_url">
            <el-input v-model="formData.a2a_endpoint_url" placeholder="请输入A2A协议端点URL" />
          </el-form-item>

          <el-form-item label="A2A版本" prop="a2a_version">
            <el-input v-model="formData.a2a_version" placeholder="请输入A2A协议版本，例如1.0.0" />
          </el-form-item>

          <el-form-item label="文档URL" prop="a2a_documentation_url">
            <el-input v-model="formData.a2a_documentation_url" placeholder="请输入文档URL（如有）" />
          </el-form-item>

          <el-form-item label="提供商信息" prop="a2a_provider">
            <el-input
              v-model="formData.a2a_provider_text"
              type="textarea"
              :rows="4"
              placeholder="请输入提供商信息（JSON格式）"
            />
          </el-form-item>

          <el-form-item label="性能指标" prop="a2a_performance">
            <el-input
              v-model="formData.a2a_performance_text"
              type="textarea"
              :rows="4"
              placeholder="请输入性能指标信息（JSON格式）"
            />
          </el-form-item>
        </template>
        <el-empty v-else description="启用A2A协议后可配置相关设置" />
      </el-card>

      <div class="form-actions">
        <el-button @click="$router.push('/agents')">取消</el-button>
        <el-button type="primary" @click="submitForm">
          {{ isEditMode ? '保存修改' : '创建智能体' }}
        </el-button>
      </div>
    </el-form>
  </div>
</template>

<script>
import { ref, computed, onMounted, watch } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { useAgentStore } from '@/store/agent'
import { ElMessage } from 'element-plus'
import axios from 'axios'
import {
  Back,
  InfoFilled
} from '@element-plus/icons-vue'

export default {
  name: 'AgentForm',
  components: {
    Back,
    InfoFilled
  },
  setup() {
    const route = useRoute()
    const router = useRouter()
    const agentStore = useAgentStore()
    const agentForm = ref(null)
    
    const isEditMode = computed(() => route.name === 'AgentEdit')
    const agentId = computed(() => route.params.id)
    
    // 从store获取状态
    const isLoading = computed(() => agentStore.isLoading)
    const error = computed(() => agentStore.error)
    
    // 表单数据
    const formData = ref({
      name: '',
      description: '',
      agent_type: 'gpt-3.5',
      model_name: '',
      is_active: true,
      
      // 凭证信息
      api_key: '',
      api_endpoint: '',
      additional_params_text: '{}',
      
      // A2A协议设置
      is_a2a_compliant: false,
      a2a_endpoint_url: '',
      a2a_version: '1.0.0',
      a2a_documentation_url: '',
      a2a_provider_text: '{}',
      a2a_performance_text: '{"latency": "medium", "throughput": "high", "availability": 0.999}'
    })
    
    // 表单验证规则
    const rules = {
      name: [
        { required: true, message: '请输入智能体名称', trigger: 'blur' },
        { min: 2, max: 100, message: '长度在2到100个字符之间', trigger: 'blur' }
      ],
      agent_type: [
        { required: true, message: '请选择智能体类型', trigger: 'change' }
      ],
      model_name: [
        { required: true, message: '请输入模型名称', trigger: 'blur' }
      ],
      api_key: [
        { required: true, message: '请输入API密钥', trigger: 'blur' }
      ],
      a2a_endpoint_url: [
        { required: false, message: '请输入A2A端点URL', trigger: 'blur' }
      ]
    }
    
    // 处理JSON字段
    const parseJsonField = (text, fallback = {}) => {
      try {
        return text ? JSON.parse(text) : fallback
      } catch (err) {
        ElMessage.warning('JSON格式不正确，请检查')
        return fallback
      }
    }
    
    // 获取智能体详情（编辑模式）
    const fetchAgentDetail = async () => {
      if (!isEditMode.value) return
      
      await agentStore.fetchAgent(agentId.value)
      
      if (agentStore.currentAgent) {
        const agentData = agentStore.currentAgent
        
        // 设置表单基础数据
        formData.value.name = agentData.name
        formData.value.description = agentData.description || ''
        formData.value.agent_type = agentData.agent_type
        formData.value.model_name = agentData.model_name
        formData.value.is_active = agentData.is_active
        
        // A2A协议数据
        formData.value.is_a2a_compliant = agentData.is_a2a_compliant || false
        formData.value.a2a_endpoint_url = agentData.a2a_endpoint_url || ''
        formData.value.a2a_version = agentData.a2a_version || '1.0.0'
        formData.value.a2a_documentation_url = agentData.a2a_documentation_url || ''
        
        // JSON数据转换为文本
        formData.value.a2a_provider_text = JSON.stringify(agentData.a2a_provider || {}, null, 2)
        formData.value.a2a_performance_text = JSON.stringify(agentData.a2a_performance || {}, null, 2)
        
        // 获取凭证信息
        if (agentData.credential) {
          formData.value.api_endpoint = agentData.credential.api_endpoint || ''
          formData.value.additional_params_text = JSON.stringify(agentData.credential.additional_params || {}, null, 2)
          // API密钥通常不会返回，需要用户重新输入
        }
      }
    }
    
    // 提交表单
    const submitForm = async () => {
      if (!agentForm.value) return
      
      await agentForm.value.validate(async (valid) => {
        if (!valid) {
          ElMessage.warning('请完善表单信息')
          return
        }
        
        try {
          // 转换JSON文本字段
          const additional_params = parseJsonField(formData.value.additional_params_text)
          const a2a_provider = parseJsonField(formData.value.a2a_provider_text)
          const a2a_performance = parseJsonField(formData.value.a2a_performance_text)
          
          // 构建请求数据
          const submitData = {
            name: formData.value.name,
            description: formData.value.description,
            agent_type: formData.value.agent_type,
            model_name: formData.value.model_name,
            is_active: formData.value.is_active,
            is_a2a_compliant: formData.value.is_a2a_compliant,
            credential: {
              api_key: formData.value.api_key,
              api_endpoint: formData.value.api_endpoint,
              additional_params: additional_params
            }
          }
          
          // 添加A2A协议数据（如果启用）
          if (formData.value.is_a2a_compliant) {
            submitData.a2a_endpoint_url = formData.value.a2a_endpoint_url
            submitData.a2a_version = formData.value.a2a_version
            submitData.a2a_documentation_url = formData.value.a2a_documentation_url
            submitData.a2a_provider = a2a_provider
            submitData.a2a_performance = a2a_performance
          }
          
          // 使用store进行保存
          if (isEditMode.value) {
            submitData.id = agentId.value
          }
          
          const result = await agentStore.saveAgent(submitData)
          
          // 跳转到详情页
          router.push(`/agents/${result.id}`)
        } catch (err) {
          console.error('保存智能体失败', err)
        }
      })
    }
    
    // 生命周期钩子
    onMounted(() => {
      fetchAgentDetail()
    })
    
    return {
      agentForm,
      formData,
      rules,
      isLoading,
      error,
      isEditMode,
      submitForm
    }
  }
}
</script>

